function signature = build_mb_figure_signature(spec)
%BUILD_MB_FIGURE_SIGNATURE Build a figure/export-layer signature for MB outputs.

if nargin < 1 || isempty(spec)
    spec = struct();
end

payload = struct( ...
    'figure_family', string(local_getfield_or(spec, 'figure_family', "")), ...
    'plot_domain_mode', string(local_getfield_or(spec, 'plot_domain_mode', "")), ...
    'plot_xlim_ns', local_getfield_or(spec, 'plot_xlim_ns', []), ...
    'plot_ylim_passratio', local_getfield_or(spec, 'plot_ylim_passratio', []), ...
    'figure_style_mode', string(local_getfield_or(spec, 'figure_style_mode', "")), ...
    'export_paper_ready', logical(local_getfield_or(spec, 'export_paper_ready', false)), ...
    'plotting_mode', string(local_getfield_or(spec, 'plotting_mode', "")), ...
    'renderer', string(local_getfield_or(spec, 'renderer', "")), ...
    'export_dpi', local_getfield_or(spec, 'export_dpi', NaN), ...
    'figure_version', string(local_getfield_or(spec, 'figure_version', "mb-figure-v1")));

signature = compute_mb_cache_input_hash(payload);
end

function value = local_getfield_or(S, field_name, fallback)
if isstruct(S) && isfield(S, field_name)
    value = S.(field_name);
else
    value = fallback;
end
end
